import{_ as a,o as d,c as l,a4 as r}from"./chunks/framework.ChErgFjV.js";const c=JSON.parse('{"title":"第二章 教育法律法规","description":"","frontmatter":{"title":"第二章 教育法律法规","date":"2026-07-06T00:00:00.000Z","tags":["教师资格考试","综合素质","法律法规"]},"headers":[],"relativePath":"study/teacher-cert/comprehensive-quality/chapter2.md","filePath":"study/teacher-cert/comprehensive-quality/chapter2.md","lastUpdated":1783652711000}'),i={name:"study/teacher-cert/comprehensive-quality/chapter2.md"};function e(o,t,h,n,s,u){return d(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="第二章-教育法律法规" tabindex="-1">第二章 教育法律法规 <a class="header-anchor" href="#第二章-教育法律法规" aria-label="Permalink to &quot;第二章 教育法律法规&quot;">​</a></h1><blockquote><p>本章考情：8-10 道选择题（16-20 分），不考大题 备考策略：不需要背条文原文，理解核心含义 + 刷选择题即可</p></blockquote><hr><h2 id="_2-1-《中华人民共和国教育法》" tabindex="-1">2.1 《中华人民共和国教育法》 <a class="header-anchor" href="#_2-1-《中华人民共和国教育法》" aria-label="Permalink to &quot;2.1 《中华人民共和国教育法》&quot;">​</a></h2><h3 id="基本信息与地位" tabindex="-1">基本信息与地位 <a class="header-anchor" href="#基本信息与地位" aria-label="Permalink to &quot;基本信息与地位&quot;">​</a></h3><ul><li><strong>地位</strong>：教育基本法、教育母法、教育的&quot;宪法&quot;</li><li><strong>施行时间</strong>：1995 年 9 月 1 日</li><li><strong>最新修订</strong>：2021 年</li></ul><h3 id="核心条款" tabindex="-1">核心条款 <a class="header-anchor" href="#核心条款" aria-label="Permalink to &quot;核心条款&quot;">​</a></h3><h4 id="教育方针" tabindex="-1">教育方针 <a class="header-anchor" href="#教育方针" aria-label="Permalink to &quot;教育方针&quot;">​</a></h4><blockquote><p>教育必须为社会主义现代化建设服务、为人民服务，必须与生产劳动和社会实践相结合，培养德智体美劳全面发展的社会主义建设者和接班人。</p></blockquote><h4 id="教育性质" tabindex="-1">教育性质 <a class="header-anchor" href="#教育性质" aria-label="Permalink to &quot;教育性质&quot;">​</a></h4><ul><li>教育是社会主义现代化建设的基础</li><li>教育属于<strong>公益性</strong>事业</li><li>教育活动必须符合国家和社会公共利益</li></ul><h4 id="受教育者权利-🔴" tabindex="-1">受教育者权利 🔴 <a class="header-anchor" href="#受教育者权利-🔴" aria-label="Permalink to &quot;受教育者权利 🔴&quot;">​</a></h4><table tabindex="0"><thead><tr><th>权利</th><th>内容</th><th>判断关键词</th></tr></thead><tbody><tr><td>参加教育教学活动权</td><td>参加教学计划安排的各种活动</td><td>上课、实验、社会实践</td></tr><tr><td>获得资助权</td><td>按规定获得奖学金、贷学金、助学金</td><td>奖学金、助学金</td></tr><tr><td>获得学业证书权</td><td>在完成学业后获得相应的学业证书</td><td>毕业证、学位证</td></tr><tr><td>申诉起诉权</td><td>对学校给予的处分不服提出申诉</td><td>申诉、起诉</td></tr><tr><td>法律法规规定的其他权利</td><td>—</td><td>—</td></tr></tbody></table><h4 id="受教育者义务" tabindex="-1">受教育者义务 <a class="header-anchor" href="#受教育者义务" aria-label="Permalink to &quot;受教育者义务&quot;">​</a></h4><ol><li>遵守法律法规</li><li>遵守学生行为规范，尊敬师长，养成良好的思想品德和行为习惯</li><li>努力学习，完成规定的学习任务</li><li>遵守所在学校或其他教育机构的管理制度</li></ol><h3 id="选择题高频考点" tabindex="-1">选择题高频考点 <a class="header-anchor" href="#选择题高频考点" aria-label="Permalink to &quot;选择题高频考点&quot;">​</a></h3><ol><li>教育法是教育&quot;母法&quot; — 地位类题目</li><li>教育公益性 — 不得以营利为目的</li><li>受教育权是公民的基本权利 — 宪法层面</li></ol><hr><h2 id="_2-2-《中华人民共和国义务教育法》" tabindex="-1">2.2 《中华人民共和国义务教育法》 <a class="header-anchor" href="#_2-2-《中华人民共和国义务教育法》" aria-label="Permalink to &quot;2.2 《中华人民共和国义务教育法》&quot;">​</a></h2><h3 id="基本信息与地位-1" tabindex="-1">基本信息与地位 <a class="header-anchor" href="#基本信息与地位-1" aria-label="Permalink to &quot;基本信息与地位&quot;">​</a></h3><ul><li><strong>地位</strong>：实施义务教育的法律保障</li><li><strong>义务教育年限</strong>：九年（小学+初中）</li><li><strong>施行时间</strong>：1986 年 7 月 1 日（2006 年修订）</li></ul><h3 id="义务教育特征-🔴" tabindex="-1">义务教育特征 🔴 <a class="header-anchor" href="#义务教育特征-🔴" aria-label="Permalink to &quot;义务教育特征 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特征</th><th>含义</th><th>判断关键词</th></tr></thead><tbody><tr><td>强制性</td><td>国家、社会、学校和家庭必须予以保证</td><td>必须、保证、不得拒绝</td></tr><tr><td>免费性</td><td>免收学费、杂费</td><td>免费、免收</td></tr><tr><td>普及性</td><td>所有适龄儿童、少年必须接受</td><td>全体、所有适龄</td></tr></tbody></table><h3 id="核心条款-1" tabindex="-1">核心条款 <a class="header-anchor" href="#核心条款-1" aria-label="Permalink to &quot;核心条款&quot;">​</a></h3><h4 id="入学制度" tabindex="-1">入学制度 <a class="header-anchor" href="#入学制度" aria-label="Permalink to &quot;入学制度&quot;">​</a></h4><ul><li>适龄儿童、少年<strong>免试就近入学</strong></li><li>地方各级人民政府保障适龄儿童、少年就近入学</li><li>禁止学校收取择校费</li></ul><h4 id="学校管理" tabindex="-1">学校管理 <a class="header-anchor" href="#学校管理" aria-label="Permalink to &quot;学校管理&quot;">​</a></h4><ul><li>不得将学校分为重点学校和非重点学校</li><li>不得分设重点班和非重点班 🔴</li><li>学校不得开除学生 🔴</li><li>学校不得违反国家规定收取费用</li></ul><h4 id="教师要求" tabindex="-1">教师要求 <a class="header-anchor" href="#教师要求" aria-label="Permalink to &quot;教师要求&quot;">​</a></h4><ul><li>教师应当尊重学生的人格，不得歧视学生</li><li>不得对学生实施体罚、变相体罚 🔴</li><li>不得侮辱学生人格尊严</li></ul><h3 id="选择题高频考点-1" tabindex="-1">选择题高频考点 <a class="header-anchor" href="#选择题高频考点-1" aria-label="Permalink to &quot;选择题高频考点&quot;">​</a></h3><ol><li>❌ &quot;重点班&quot; → ✅ 不得分重点班和非重点班</li><li>❌ 开除违纪学生 → ✅ 不得开除学生</li><li>免费范围 = 学费 + 杂费（不含住宿费、伙食费）</li><li>义务教育责任主体 = 政府、社会、学校、家庭四方</li></ol><hr><h2 id="_2-3-《中华人民共和国教师法》" tabindex="-1">2.3 《中华人民共和国教师法》 <a class="header-anchor" href="#_2-3-《中华人民共和国教师法》" aria-label="Permalink to &quot;2.3 《中华人民共和国教师法》&quot;">​</a></h2><h3 id="基本信息与地位-2" tabindex="-1">基本信息与地位 <a class="header-anchor" href="#基本信息与地位-2" aria-label="Permalink to &quot;基本信息与地位&quot;">​</a></h3><ul><li><strong>地位</strong>：维护教师合法权益的法律</li><li><strong>施行时间</strong>：1994 年 1 月 1 日</li><li><strong>教师节</strong>：9 月 10 日（本法确定）</li></ul><h3 id="教师权利-🔴🔴" tabindex="-1">教师权利 🔴🔴 <a class="header-anchor" href="#教师权利-🔴🔴" aria-label="Permalink to &quot;教师权利 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>权利</th><th>内容</th><th>判断关键词</th></tr></thead><tbody><tr><td>教育教学权</td><td>开展教育教学改革和实验</td><td>上课、教学改革</td></tr><tr><td>学术研究权</td><td>从事科学研究、学术交流</td><td>论文、研究、学术</td></tr><tr><td>指导评价权</td><td>指导学生的学习和发展，评定学生的品行和学业成绩</td><td>评价、评定</td></tr><tr><td>获取报酬权</td><td>按时获取工资报酬，享受国家规定的福利待遇</td><td>工资、福利、寒暑假带薪</td></tr><tr><td>民主管理权</td><td>对学校教育教学、管理工作提出意见和建议</td><td>建议、参与管理</td></tr><tr><td>进修培训权</td><td>参加进修或者其他方式的培训</td><td>培训、进修</td></tr></tbody></table><h3 id="教师义务" tabindex="-1">教师义务 <a class="header-anchor" href="#教师义务" aria-label="Permalink to &quot;教师义务&quot;">​</a></h3><ol><li>遵守宪法、法律和职业道德</li><li>完成教育教学工作任务</li><li>对学生进行思想品德教育</li><li>关心爱护全体学生，尊重学生人格</li><li>制止有害于学生的行为</li><li>不断提高思想政治觉悟和教育教学业务水平</li></ol><h3 id="教师资格制度" tabindex="-1">教师资格制度 <a class="header-anchor" href="#教师资格制度" aria-label="Permalink to &quot;教师资格制度&quot;">​</a></h3><ul><li>取得教师资格的条件：中国公民 + 思想品德良好 + 学历合格 + 教育教学能力</li><li>教师资格分类：幼儿园、小学、初中、高中、中职、高校</li><li>教师资格丧失：故意犯罪受刑事处罚 → 丧失教师资格，不能重新取得</li></ul><h3 id="选择题高频考点-2" tabindex="-1">选择题高频考点 <a class="header-anchor" href="#选择题高频考点-2" aria-label="Permalink to &quot;选择题高频考点&quot;">​</a></h3><ol><li>寒暑假带薪休假 → 获取报酬权</li><li>教师资格丧失 = 故意犯罪 + 刑事处罚</li><li>教师申诉制度 — 对学校处理不服，30 日内向教育行政部门申诉</li></ol><hr><h2 id="_2-4-《中华人民共和国未成年人保护法》" tabindex="-1">2.4 《中华人民共和国未成年人保护法》 <a class="header-anchor" href="#_2-4-《中华人民共和国未成年人保护法》" aria-label="Permalink to &quot;2.4 《中华人民共和国未成年人保护法》&quot;">​</a></h2><h3 id="基本信息与地位-3" tabindex="-1">基本信息与地位 <a class="header-anchor" href="#基本信息与地位-3" aria-label="Permalink to &quot;基本信息与地位&quot;">​</a></h3><ul><li><strong>未成年年龄</strong>：未满 18 周岁</li><li><strong>保护原则</strong>：最有利于未成年人</li><li><strong>最新修订</strong>：2020 年（2021 年 6 月 1 日施行）</li></ul><h3 id="六大保护-🔴🔴" tabindex="-1">六大保护 🔴🔴 <a class="header-anchor" href="#六大保护-🔴🔴" aria-label="Permalink to &quot;六大保护 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>保护类型</th><th>责任主体</th><th>核心内容</th><th>判断关键词</th></tr></thead><tbody><tr><td>家庭保护</td><td>父母或其他监护人</td><td>抚养、教育、保护</td><td>父母、监护人</td></tr><tr><td>学校保护</td><td>学校、幼儿园</td><td>安全、教育、身心健康</td><td>学校、教师</td></tr><tr><td>社会保护</td><td>全社会</td><td>创造良好社会环境</td><td>社会各界</td></tr><tr><td>网络保护 🔴</td><td>国家、社会、学校、家庭</td><td>防沉迷、信息保护</td><td>网络、防沉迷</td></tr><tr><td>政府保护</td><td>各级人民政府</td><td>保障权益、提供服务</td><td>政府、民政</td></tr><tr><td>司法保护</td><td>公检法机关</td><td>办案中的特殊保护</td><td>法院、检察院</td></tr></tbody></table><h3 id="核心条款-2" tabindex="-1">核心条款 <a class="header-anchor" href="#核心条款-2" aria-label="Permalink to &quot;核心条款&quot;">​</a></h3><ol><li><strong>不得招用未满 16 周岁的未成年人</strong> 🔴</li><li><strong>营业性歌舞娱乐场所不得允许未成年人进入</strong></li><li><strong>不得向未成年人出售烟酒</strong> 🔴</li><li><strong>学校不得违反规定开除未成年学生</strong></li><li><strong>对未成年人案件不公开审理</strong></li></ol><h3 id="选择题高频考点-3" tabindex="-1">选择题高频考点 <a class="header-anchor" href="#选择题高频考点-3" aria-label="Permalink to &quot;选择题高频考点&quot;">​</a></h3><ol><li>未成年 = 未满 18 岁</li><li>禁止招工年龄线 = 16 岁（非 18 岁）</li><li>六大保护中&quot;网络保护&quot;是 2021 年新增</li><li>最有利于未成年人原则 — 一切工作的出发点</li></ol><hr><h2 id="_2-5-其他重要法律" tabindex="-1">2.5 其他重要法律 <a class="header-anchor" href="#_2-5-其他重要法律" aria-label="Permalink to &quot;2.5 其他重要法律&quot;">​</a></h2><h3 id="《预防未成年人犯罪法》" tabindex="-1">《预防未成年人犯罪法》 <a class="header-anchor" href="#《预防未成年人犯罪法》" aria-label="Permalink to &quot;《预防未成年人犯罪法》&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为类型</th><th>具体表现</th><th>处置方式</th></tr></thead><tbody><tr><td>一般不良行为</td><td>旷课、夜不归宿、打架、强行索要财物</td><td>学校+家长教育</td></tr><tr><td>严重不良行为</td><td>多次偷盗、参与赌博、携带管制刀具</td><td>公安机关介入</td></tr><tr><td>犯罪行为</td><td>触犯刑法</td><td>司法程序</td></tr></tbody></table><p><strong>关键区分</strong>：不良行为 vs 严重不良行为 — 看是否&quot;严重危害社会&quot;</p><h3 id="《学生伤害事故处理办法》" tabindex="-1">《学生伤害事故处理办法》 <a class="header-anchor" href="#《学生伤害事故处理办法》" aria-label="Permalink to &quot;《学生伤害事故处理办法》&quot;">​</a></h3><ul><li><strong>归责原则</strong>：过错责任原则 🔴</li><li>学校承担责任的情形： <ul><li>学校设施存在安全隐患</li><li>学校组织活动未采取安全措施</li><li>教师体罚或变相体罚</li></ul></li><li>学校不承担责任的情形： <ul><li>学生自行上学放学途中</li><li>学生擅自离校期间</li><li>不可抗力</li></ul></li></ul><h3 id="《国家中长期教育改革发展规划纲要》-2010-2020" tabindex="-1">《国家中长期教育改革发展规划纲要》（2010-2020） <a class="header-anchor" href="#《国家中长期教育改革发展规划纲要》-2010-2020" aria-label="Permalink to &quot;《国家中长期教育改革发展规划纲要》（2010-2020）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要点</th><th>内容</th></tr></thead><tbody><tr><td>战略主题</td><td>坚持以人为本、全面实施素质教育</td></tr><tr><td>战略目标</td><td>基本实现教育现代化、基本形成学习型社会、进入人力资源强国行列</td></tr><tr><td>工作方针</td><td>优先发展、育人为本、改革创新、促进公平、提高质量</td></tr><tr><td>核心理念</td><td>育人为本 🔴</td></tr></tbody></table><hr><h2 id="_2-6-法律法规速查表" tabindex="-1">2.6 法律法规速查表 <a class="header-anchor" href="#_2-6-法律法规速查表" aria-label="Permalink to &quot;2.6 法律法规速查表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>法律</th><th>施行时间</th><th>核心关键词</th></tr></thead><tbody><tr><td>教育法</td><td>1995.9.1</td><td>教育母法、公益性</td></tr><tr><td>义务教育法</td><td>1986.7.1</td><td>九年、免费、强制</td></tr><tr><td>教师法</td><td>1994.1.1</td><td>六大权利、资格制度</td></tr><tr><td>未成年人保护法</td><td>2007.6.1</td><td>六大保护、未满18岁</td></tr><tr><td>预防未成年人犯罪法</td><td>1999.11.1</td><td>不良→严重不良→犯罪</td></tr><tr><td>学生伤害事故处理办法</td><td>2002.9.1</td><td>过错责任原则</td></tr></tbody></table><h3 id="法律条文判断技巧" tabindex="-1">法律条文判断技巧 <a class="header-anchor" href="#法律条文判断技巧" aria-label="Permalink to &quot;法律条文判断技巧&quot;">​</a></h3><ol><li>看到&quot;必须&quot;&quot;不得&quot;&quot;禁止&quot; → 义务性条款</li><li>看到&quot;有权&quot;&quot;可以&quot;&quot;享受&quot; → 权利性条款</li><li>看到具体年龄 → 对比：16 岁（招工线）、18 岁（成年线）、9 年（义务教育）</li><li>看到归责 → 学生伤害 = 过错责任（谁错谁赔）</li></ol>',68)])])}const q=a(i,[["render",e]]);export{c as __pageData,q as default};
